export const customDateFormat = (date) => {
    const dateFields = { 
        year: 'numeric', 
        month: 'short', 
        day: 'numeric',
        weekday: 'long'
    };

    const formattedDate = new Date(date).toLocaleDateString('en-US', {dateFields, timeZone: 'UTC' });
    console.log(formattedDate);
    return formattedDate;
}
